window.codeFormatter = {
    format: function(code, language) {
        var lang = language.toLowerCase();
        
        if (lang === 'json') {
            return this.formatJson(code);
        }
        
        if (lang === 'python') {
            return this.formatPython(code);
        }
        
        if (['java', 'cpp', 'c', 'csharp', 'javascript', 'typescript', 'js', 'ts'].includes(lang)) {
            return this.formatBraces(code);
        }
        
        return code;
    },
    
    formatPython: function(code) {
        return code;
    },
    
    formatBraces: function(code) {
        var lines = code.split('\n');
        var result = [];
        var indent = 0;
        var braceStack = [];
        
        lines.forEach(function(line) {
            var trimmed = line.trim();
            if (!trimmed) {
                result.push('');
                return;
            }
            
            var processed = trimmed;
            var openCount = (processed.match(/\{/g) || []).length;
            var closeCount = (processed.match(/\}/g) || []).length;
            
            for (var i = 0; i < closeCount; i++) {
                if (braceStack.length > 0) {
                    braceStack.pop();
                }
            }
            
            var currentIndent = braceStack.length;
            result.push('    '.repeat(currentIndent) + processed);
            
            for (var i = 0; i < openCount; i++) {
                braceStack.push('{');
            }
        });
        
        return result.join('\n');
    },
    
    formatJson: function(code) {
        try {
            return JSON.stringify(JSON.parse(code), null, 4);
        } catch (e) {
            return code;
        }
    }
};